```javascript
/**
 * 创建一个防抖函数 (debounce)
 * 
 * 在连续触发事件时，只在最后一次触发后的 wait 毫秒后执行回调。
 * 如果在等待期间再次触发，则重新计时。
 *
 * @param {Function} fn       - 需要防抖的回调函数
 * @param {number}   wait     - 延迟执行毫秒数
 * @param {Object}   options  - 可选配置
 * @param {boolean}  options.leading  - 是否在开始前先执行一次 (默认 false)
 * @param {boolean}  options.trailing - 是否在结束后执行一次 (默认 true)
 * @returns {Function} 返回防抖后的函数，附带 .cancel() 和 .flush() 方法
 */
function debounce(fn, wait, options = {}) {
  const { leading = false, trailing = true } = options;

  let timer = null;           // 定时器句柄
  let lastArgs = null;        // 最后一次调用参数
  let lastThis = null;        // 最后一次调用上下文
  let result = undefined;     // 返回值
  let isInvoked = false;      // leading 模式下是否已执行过

  // 执行回调
  function invokeFunc(time) {
    const args = lastArgs;
    const thisArg = lastThis;

    lastArgs = lastThis = null;
    isInvoked = true;
    result = fn.apply(thisArg, args);
    return result;
  }

  // 开启定时器（trailing 调用）
  function startTimer(pendingExpiry) {
    timer = setTimeout(() => {
      timer = null;

      // trailing 模式且还有待执行参数
      if (trailing && lastArgs) {
        return invokeFunc();
      }

      // 没有待执行参数，重置 leading 状态
      isInvoked = false;
      lastArgs = lastThis = null;
    }, wait);

    // 如果传入了 expiry 时间戳，不在这里处理
  }

  // 开始执行 leading 调用
  function leadingEdge(time) {
    isInvoked = true;          // 标记已执行 leading
    timer = setTimeout(() => {
      timer = null;

      // trailing 边缘处理
      if (trailing && lastArgs) {
        return invokeFunc();
      }
      // 重置状态
      isInvoked = false;
      lastArgs = lastThis = null;
    }, wait);

    return invokeFunc(time);
  }

  // 防抖主函数
  function debounced(...args) {
    const time = Date.now();
    lastArgs = args;
    lastThis = this;

    // 首次调用或 leading 模式
    if (timer === null) {
      if (leading) {
        return leadingEdge(time);
      }
      // trailing 模式，启动定时器
      startTimer(wait);
      return result;
    }

    // 已有定时器：重新计时（标准的 debounce 行为）
    clearTimeout(timer);
    startTimer(wait);

    return result;
  }

  // 取消当前等待的调用
  debounced.cancel = function () {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    lastArgs = lastThis = null;
    isInvoked = false;
    result = undefined;
  };

  // 立即执行等待中的调用
  debounced.flush = function () {
    if (timer !== null && lastArgs) {
      clearTimeout(timer);
      timer = null;
      return invokeFunc();
    }
    return result;
  };

  // 是否在等待定时器
  debounced.isPending = function () {
    return timer !== null;
  };

  return debounced;
}

// =========== 使用示例 ===========

// 1. 基本用法：输入框防抖
const searchInput = document.querySelector('#search');
const handleSearch = debounce((event) => {
  console.log('发起搜索:', event.target.value);
  // API.search(event.target.value);
}, 300);

searchInput.addEventListener('input', handleSearch);

// 2. leading 模式：点击按钮立即执行，但防抖后续连续点击
const saveBtn = document.querySelector('#save');
const handleSave = debounce(
  () => console.log('保存数据...'),
  2000,
  { leading: true, trailing: false }
);
saveBtn.addEventListener('click', handleSave);

// 3. 取消/立即执行
const debouncedFn = debounce(() => console.log('执行'), 5000);
debouncedFn();          // 开始 5s 倒计时
debouncedFn.cancel();   // 取消
debouncedFn();          // 重新计时
debouncedFn.flush();    // 立即执行

// 4. 配合 async/await
const asyncDebounce = debounce(async (query) => {
  const res = await fetch(`/api/search?q=${query}`);
  return res.json();
}, 500);

// 5. React hooks 风格封装
function useDebounce(value, delay) {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedValue(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debouncedValue;
}
```

## 核心要点

| 特性 | 说明 |
|------|------|
| **trailing** (默认) | 快速连续触发后，等待 `wait` 毫秒无新触发，执行最后一次 |
| **leading** | 第一次触发时**立即执行**，后续连续触发被忽略，直到冷却结束 |
| **`.cancel()`** | 取消尚未执行的 trailing 调用 |
| **`.flush()`** | 立即执行 pending 中的调用 |
| **`.isPending()`** | 检查当前是否在等待定时器 |

**与 throttle 的区别：**
- **Debounce**：连续触发只执行**最后一次**（或第一次 + 最后一次）
- **Throttle**：固定频率执行，保证**至少执行一次**（如每 200ms 一次）

